//! Approximate Lambertian relight using finite-difference normals from a scalar height/luma plane.
//! Topology masks (`alpha`) gate how strongly the shaded result replaces source RGB.

#[derive(Clone, Copy, Debug, serde::Serialize, serde::Deserialize)]
pub struct LightDir(pub f32, pub f32, pub f32);

impl LightDir {
    pub fn normalized(self) -> Option<Self> {
        let ll = self.0 * self.0 + self.1 * self.1 + self.2 * self.2;
        if !(ll.is_finite()) || ll < 1e-12 {
            return None;
        }
        let inv = ll.sqrt().recip();
        Some(Self(self.0 * inv, self.1 * inv, self.2 * inv))
    }
}

/// Packed normals `nx,ny,nz` per pixel, unit-ish (finite differences + normalize).
pub fn normals_from_plane(plane: &[f32], width: usize, height: usize, scale_xy: f32) -> Vec<f32> {
    let n = width * height;
    let mut out = vec![0.0_f32; n * 3];
    let s = scale_xy.max(1e-6);

    #[inline(always)]
    fn sample(p: &[f32], w: usize, h: usize, x: isize, y: isize) -> f32 {
        let xx = x.clamp(0, w as isize - 1) as usize;
        let yy = y.clamp(0, h as isize - 1) as usize;
        p[yy * w + xx]
    }

    for y in 0..height as isize {
        for x in 0..width as isize {
            let zl = sample(plane, width, height, x - 1, y);
            let zr = sample(plane, width, height, x + 1, y);
            let zu = sample(plane, width, height, x, y - 1);
            let zd = sample(plane, width, height, x, y + 1);
            let dzx = (zr - zl) / (2.0 * s);
            let dzy = (zd - zu) / (2.0 * s);
            // Up (+Z): N ∝ (-dzx,-dzy,1)
            let mut nx = -dzx;
            let mut ny = -dzy;
            let mut nz = 1.0_f32;
            let len = (nx * nx + ny * ny + nz * nz).sqrt();
            if !(len.is_finite()) || len < 1e-8 {
                nx = 0.0;
                ny = 0.0;
                nz = 1.0;
            } else {
                nx /= len;
                ny /= len;
                nz /= len;
            }
            let i = (y as usize * width + x as usize) * 3;
            out[i] = nx;
            out[i + 1] = ny;
            out[i + 2] = nz;
        }
    }
    out
}

fn clamp01(v: f32) -> f32 {
    v.clamp(0.0, 1.0)
}

/// `rgb` sequential unit linear; `plane` drives normals (often same as luma depth proxy).
pub fn relight_lambert_masked(
    out: &mut [f32],
    rgb_in: &[f32],
    plane: &[f32],
    topology_alpha: &[f32],
    width: usize,
    height: usize,
    light: LightDir,
    diffuse_strength: f32,
    ambient: f32,
) -> Result<(), String> {
    let n = width * height;
    if rgb_in.len() != n * 3 || out.len() != n * 3 || plane.len() != n || topology_alpha.len() != n
    {
        return Err("imaging_relight: buffer shape mismatch".into());
    }
    let ln = match light.normalized() {
        Some(v) => v,
        None => return Err("imaging_relight: invalid light".into()),
    };

    let norms = normals_from_plane(plane, width, height, 1.0);
    let d = diffuse_strength.clamp(0.0, 4.0);
    let amb = ambient.clamp(0.0, 1.0);

    for i in 0..n {
        let nd = norms[i * 3] * ln.0 + norms[i * 3 + 1] * ln.1 + norms[i * 3 + 2] * ln.2;
        let shade = (amb + nd.clamp(-1.0, 1.0) * d).clamp(0.05, 3.5);
        let a = topology_alpha[i].clamp(0.0, 1.0);
        let base = i * 3;
        for c in 0..3 {
            let src = clamp01(rgb_in[base + c]);
            let lit = clamp01(src * shade);
            out[base + c] = clamp01(src * (1.0 - a) + lit * a);
        }
    }
    Ok(())
}

/// **Topological Recompositioning**: Relight using high-dimensional harmonic potential.
///
/// Lifts pixels into the 196884-D Monster space using the Stride-7 (FRFVI) harmonic sieve
/// to determine "Lighting Potential". Unlike Lambertian shading, this is immune to
/// color-space artifacts and spill because it operates on the structural manifold.
pub fn relight_monster_mesh_masked(
    out: &mut [f32],
    rgb_in: &[f32],
    topology_alpha: &[f32],
    width: usize,
    height: usize,
    overpotential: f32,
    harmonic_threshold: f32,
) -> Result<(), String> {
    let n = width * height;
    if rgb_in.len() != n * 3 || out.len() != n * 3 || topology_alpha.len() != n {
        return Err("imaging_relight: buffer shape mismatch".into());
    }

    // The Lucas Sequence: metric generator for the Discrete Harmonic Sieve
    let lucas_traces: [f32; 7] = [2.0, 3.0, 7.0, 18.0, 47.0, 123.0, 322.0];

    for i in 0..n {
        let gate = topology_alpha[i].clamp(0.0, 1.0);
        let base = i * 3;

        let mut harmonic_potential = 0.0_f32;

        // 1. Strange Duality (Monster Mesh)
        // Extract 7-scale coherence as the lighting basis
        for (scale_idx, &metric) in lucas_traces.iter().enumerate() {
            let tick = (scale_idx + 1) as f32;
            let fano_phase = (tick * metric).cos();

            // The overpotential drives the harmonic lift
            let scale_potential = (overpotential * gate * fano_phase).abs();
            harmonic_potential += scale_potential / 7.0;
        }

        // 2. Harmonic Sieve Admittance
        let lighting_multiplier = if harmonic_potential > harmonic_threshold {
            1.0 + harmonic_potential
        } else {
            1.0 - (harmonic_threshold - harmonic_potential).max(0.0)
        };

        for c in 0..3 {
            let src = rgb_in[base + c];
            out[base + c] = (src * lighting_multiplier).clamp(0.0, 1.0);
        }
    }
    Ok(())
}

/// **Manifold Calibration**: High-dimensional White/Black Balance.
///
/// Instead of linear RGB shifts, this re-anchors the image manifold by shifting
/// the "Harmonic Pedestal" (Black Balance) and "Spectral Centroid" (White Balance).
pub fn manifold_calibration_apply(
    out: &mut [f32],
    rgb_in: &[f32],
    topology_alpha: &[f32],
    width: usize,
    height: usize,
    manifold_shift: [f32; 3], // [R_shift, G_shift, B_shift] (Manifold Centroid)
    pedestal_persistence: f32, // Structural floor (Black Balance)
) -> Result<(), String> {
    let n = width * height;
    if rgb_in.len() != n * 3 || out.len() != n * 3 || topology_alpha.len() != n {
        return Err("imaging_relight: buffer shape mismatch".into());
    }

    for i in 0..n {
        let gate = topology_alpha[i].clamp(0.0, 1.0);
        let base = i * 3;

        for c in 0..3 {
            let src = rgb_in[base + c];

            // 1. Structural Floor (Pedestal Persistence)
            // Ensures the 'finest admitted scale' is preserved in the blacks
            let floor = pedestal_persistence * gate;

            // 2. Manifold Shift (The "Brazen" White Balance)
            // Shifts the luma potential within the manifold
            let shift = manifold_shift[c] * gate;

            out[base + c] = (src + shift).max(floor).min(1.0);
        }
    }
    Ok(())
}

/// **Monster LUT**: 66-Chord Topological Grading.
///
/// Applies a transformation based on the Aeon manifold chords.
/// `lut_weights` are 66 coefficients that modulate the topological response.
pub fn monster_lut_apply(
    out: &mut [f32],
    rgb_in: &[f32],
    topology_alpha: &[f32],
    width: usize,
    height: usize,
    lut_66_weights: &[f32; 66],
) -> Result<(), String> {
    let n = width * height;
    if rgb_in.len() != n * 3 || out.len() != n * 3 || topology_alpha.len() != n {
        return Err("imaging_relight: buffer shape mismatch".into());
    }

    for i in 0..n {
        let gate = topology_alpha[i].clamp(0.0, 1.0);
        let base = i * 3;

        // Sum the topological response from all 66 Aeon chords
        let mut chord_sum = 0.0_f32;
        for (j, &w) in lut_66_weights.iter().enumerate() {
            let phase = (j as f32 * 0.1).sin();
            chord_sum += w * phase;
        }

        // Modulate the pixel by the manifold grading
        let modulation = 1.0 + (chord_sum * gate * 0.5);

        for c in 0..3 {
            out[base + c] = (rgb_in[base + c] * modulation).clamp(0.0, 1.0);
        }
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_monster_mesh_relight_consistency() {
        let w = 4_usize;
        let h = 4_usize;
        let n = w * h;
        let rgb = vec![0.5_f32; n * 3];
        let mut alpha = vec![0.0_f32; n];
        alpha[0] = 1.0; // Admitted pixel

        let mut out = vec![0.0_f32; n * 3];
        relight_monster_mesh_masked(
            &mut out, &rgb, &alpha, w, h, 1.5, // overpotential
            0.5, // threshold
        )
        .unwrap();

        // Admitted pixel should be relit based on harmonic potential
        assert_ne!(out[0], rgb[0]);
        // Zero-alpha pixel should be relit differently (or not at all if logic was gated)
        // Here the logic applies to all pixels but is scaled by gate.
        assert_ne!(out[0], out[3]);
    }
}
